<style id='intlTelInput-css-inline-css'>

    /* wrapper (.iti) ko hi use karenge */
    #wpforms-form-12352 .phone-wrapper-custom {
        position: relative;
        display: flex;
        align-items: center;
        gap: 10px;
        border-bottom: 1px solid rgba(0,0,0,0.25) !important;
        padding: 6px 0;
    }

    /* left side country selector text / value */
    #wpforms-form-12352 .phone-wrapper-custom .custom-selected-dial {
        min-width: 120px;
        cursor: pointer;
        font-size: 14px;
        color: #555;
        display: flex;
        align-items: center;
        gap: 6px;
    }

    #wpforms-form-12352 .phone-wrapper-custom .custom-selected-dial span.placeholder {
        color: #B0B0B0;
        font-weight: 500;
        display: flex;
        align-items: center;
        gap: 4px;
    }

    #wpforms-form-12352 .phone-wrapper-custom .custom-selected-dial .iti__flag-box {
        width: 20px;
        height: 15px;
        overflow: hidden;
    }

    #wpforms-form-12352 .phone-wrapper-custom .custom-selected-dial .iti__flag {
        display: block;
    }

    /* actual input */
    #wpforms-form-12352 #wpforms-12352-field_4 {
        flex: 1;
        border: none !important;
        outline: none !important;
        padding: 6px 0 !important;
        margin: 0 !important;
        box-shadow: none !important;
        background: transparent !important;
    }

    /* CUSTOM DROPDOWN RESET */
    #wpforms-form-12352 .custom-country-dropdown {
        list-style: none;
        position: absolute;
        top: 100%;
        left: 0;
        z-index: 99999;
        background: #fff;
        border: 1px solid #ccc;
        max-height: 235px;
        overflow-y: auto;
        padding: 0;
        margin: 4px 0 0;
        width: 98%;
        display: none;
        box-shadow: 0 4px 10px rgba(0,0,0,0.1);
    }
    #wpforms-form-12352 .custom-country-dropdown li {
        display: flex !important;
        align-items: center;
        gap: 8px;
        padding: 6px 10px;
        border-bottom: 1px solid #eee;
        font-size: 14px;
        line-height: 1.4;
        white-space: nowrap;
        cursor: pointer;
    }
    #wpforms-form-12352 .custom-country-dropdown li:hover {
        background: #f0f0f0;
    }
    #wpforms-form-12352 .custom-country-dropdown li .iti__flag-box {
        width: 20px;
        height: 15px;
        overflow: hidden;
    }
    #wpforms-form-12352 .custom-country-dropdown li .iti__flag {
        display: block;
    }
    #wpforms-form-12352 .custom-country-dropdown li strong {
        min-width: 42px;
        font-weight: 600;
    }

    /* error text */
    #wpforms-form-12352 .custom-phone-error {
        color: #d63637;
        font-size: 13px;
        font-weight: 500;
        margin-top: 4px;
        display: none;
    }

    /* intl-tel-input default flag-container hide (hum apna custom use kar rahe) */
    .pop-up-container .iti__flag-container {
        display: none !important;
    }

    /* .iti container par extra background/border hatana */
    .iti.iti--allow-dropdown.iti--separate-dial-code {
        border: none !important;
        background: none !important;
    }
    
/*# sourceURL=intlTelInput-css-inline-css */
</style>
