    transition: transform 0.3s ease !important;
}

/* Open state – rotate icon */
.jltma-advanced-accordion 
.jltma-accordion-header.active 
.jltma-accordion-title-icon::after,
.jltma-advanced-accordion 
.jltma-accordion-header[aria-expanded="true"] 
