        <script>
    jQuery(document).ready(function ($) {
        // === Forms and textareas to validate ===
        const textareaForms = [
            { form: "#wpforms-form-12352", textarea: "#wpforms-12352-field_2" },
            { form: "#wpforms-form-10740", textarea: "#wpforms-10740-field_2" },
            { form: "#wpforms-form-20583", textarea: "#wpforms-20583-field_2" },
        ];

        textareaForms.forEach(item => {
            const $form = $(item.form);
            const $textarea = $(item.textarea);

            if (!$form.length || !$textarea.length) return;

            // WPForms ke native submit handler ka use karein
            $form.on("wpformsBeforeFormSubmit", function (e) {
                
                // 1. Check if WPForms default validation is passed
                const validator = $form.validate();
                if (!validator.form()) {
                    return; // Baaki errors dikhne do, yahan ruk jao
                }

                const value = $textarea.val().trim();
                const words = value.split(/\s+/).filter(word => word.length > 0);
                const errorClass = "wpforms-error-text-custom";

                // Remove old error if any
                $textarea.removeClass("wpforms-error-custom");
                $form.find("." + errorClass).remove();

                // 2. Word Count Check (At least 5 words)
                if (words.length < 5) {
                    // Show inline error
                    const errorMsg = $('<div class="' + errorClass + '">Please enter at least 5 words before submitting.</div>');
                    
                    $textarea.addClass("wpforms-error-custom");
                    $textarea.after(errorMsg);
                    
                    // Scroll to textarea
                    $('html, body').animate({
                        scrollTop: $textarea.offset().top - 100
                    }, 500);

                    return false; // STOP FORM SUBMISSION
                }

                return true; // PROCEED SUBMISSION
            });

            // Real-time error removal
            $textarea.on("input", function() {
                if ($(this).val().trim().split(/\s+/).length >= 5) {
                    $(this).removeClass("wpforms-error-custom");
                    $form.find(".wpforms-error-text-custom").remove();
                }
            });
        });
    });
