    			<script>
				const lazyloadRunObserver = () => {
					const lazyloadBackgrounds = document.querySelectorAll( `.e-con.e-parent:not(.e-lazyloaded)` );
					const lazyloadBackgroundObserver = new IntersectionObserver( ( entries ) => {
						entries.forEach( ( entry ) => {
							if ( entry.isIntersecting ) {
								let lazyloadBackground = entry.target;
								if( lazyloadBackground ) {
									lazyloadBackground.classList.add( 'e-lazyloaded' );
								}
								lazyloadBackgroundObserver.unobserve( entry.target );
							}
						});
					}, { rootMargin: '200px 0px 200px 0px' } );
					lazyloadBackgrounds.forEach( ( lazyloadBackground ) => {
						lazyloadBackgroundObserver.observe( lazyloadBackground );
					} );
				};
				const events = [
					'DOMContentLoaded',
					'elementor/lazyload/observe',
				];
				events.forEach( ( event ) => {
					document.addEventListener( event, lazyloadRunObserver );
				} );
			</script>
			<script>document.addEventListener("DOMContentLoaded", function () {
  const submenuParents = document.querySelectorAll(".xpro-elementor-dropdown-menu .dropdown");

  submenuParents.forEach(function(parentLi) {
    parentLi.addEventListener("mouseenter", function() {

       // ✅ Mobile par script stop karne ke liye (1024px tak skip)
      if (window.innerWidth <= 767) return;
      
      // ✅ FIX: Body ko hilne se rokne ke liye
      document.body.style.setProperty("overflow", "visible", "important");
      document.body.style.setProperty("padding-right", "0px", "important");

      const submenu = parentLi.querySelector(":scope > .xpro-elementor-dropdown-menu");
      
      // ✅ Highlight parent row
      parentLi.classList.add("is-active-parent");

      if (!submenu) return;

      submenu.style.removeProperty("top");
      submenu.style.removeProperty("bottom");
      submenu.style.removeProperty("max-height");
      submenu.style.removeProperty("overflow-y");

      setTimeout(() => {
        const mainMenu = parentLi.closest(".nav-item > .xpro-elementor-dropdown-menu");
        if (!mainMenu) return;

        const parentRect = parentLi.getBoundingClientRect();
        const mainMenuRect = mainMenu.getBoundingClientRect();
        const viewportHeight = window.innerHeight;
        const submenuHeight = submenu.scrollHeight;

        const highestAllowedTop = (mainMenuRect.top - parentRect.top);
        let targetTop = 0;

        if (parentRect.top + submenuHeight > viewportHeight - 20) {
          targetTop = (viewportHeight - submenuHeight - 20) - parentRect.top;
          targetTop = Math.max(targetTop, highestAllowedTop);
        }

        submenu.style.setProperty("top", targetTop + "px", "important");
        submenu.style.setProperty("bottom", "auto", "important");

        let absoluteTopAfterShift = parentRect.top + targetTop;
        if (absoluteTopAfterShift + submenuHeight > viewportHeight - 20) {
          let availableHeight = viewportHeight - absoluteTopAfterShift - 20;
          submenu.style.setProperty("max-height", availableHeight + "px", "important");
          submenu.style.setProperty("overflow-y", "auto", "important");
        }
      }, 10);
    });

    parentLi.addEventListener("mouseleave", function() {
       if (window.innerWidth <= 767) return;
      // ✅ Reset highlight and body stability
      parentLi.classList.remove("is-active-parent");
      document.body.style.removeProperty("overflow");
      document.body.style.removeProperty("padding-right");

      const submenu = parentLi.querySelector(":scope > .xpro-elementor-dropdown-menu");
      if (submenu) {
        submenu.style.removeProperty("top");
        submenu.style.removeProperty("bottom");
        submenu.style.removeProperty("max-height");
        submenu.style.removeProperty("overflow-y");
        submenu.style.removeProperty("padding-right");
      }
    });
  });
});











