    // ------------------ RESPONSIVE POSITION FIX (mobile + extended laptop up to 1600px) ------------------
    // Move the country list into the itiContainer for mobile and laptop widths (<=1600px).
    function moveCountryListToContainerForSmallAndLaptop() {
        try {
            const w = window.innerWidth || document.documentElement.clientWidth;
            // mobile: <=768; laptops: 769 - 1600 (covers 1360,1366,1440,1536,1600)
            if (w > 1600) return; // do nothing for very large desktops / wide screens

            const countryList = document.querySelector(".iti__country-list");
            if (!countryList) return;

            // Move inside container if needed
            if (!itiContainer.contains(countryList)) {
                itiContainer.appendChild(countryList);
            }

            // Basic inline styles for good placement inside container
            countryList.style.position = "absolute";
            countryList.style.top = "calc(100% + 6px)";
            countryList.style.left = "0";
            countryList.style.width = "100%";
            countryList.style.maxHeight = (w <= 768 ? "200px" : "280px");
            countryList.style.overflowY = "auto";
            countryList.style.webkitOverflowScrolling = "touch";
            countryList.style.zIndex = "99999";
            countryList.classList.remove("iti--fixed");
        } catch (err) {
            // silent
        }
    }

    // MutationObserver: if plugin dynamically creates/moves the country list later, catch it and move inside.
    (function setupItiCountryListObserver(){
        try {
            const observer = new MutationObserver(function(mutations){
                const w = window.innerWidth || document.documentElement.clientWidth;
                if (w > 1600) return; // ignore for very wide desktops

                for (const m of mutations) {
                    // react only when nodes are added (lightweight)
                    if (m.addedNodes && m.addedNodes.length) {
                        m.addedNodes.forEach(function(node){
                            if (!(node instanceof HTMLElement)) return;
                            if (node.matches && node.matches('.iti__country-list')) {
                                setTimeout(moveCountryListToContainerForSmallAndLaptop, 30);
                            } else {
                                const found = node.querySelector && node.querySelector('.iti__country-list');
                                if (found) {
                                    setTimeout(moveCountryListToContainerForSmallAndLaptop, 30);
                                }
                            }
                        });
                    }
                    // sometimes an attribute change may result in list being moved/modified
                    if (m.target && m.target.querySelector) {
                        const found = m.target.querySelector('.iti__country-list');
                        if (found) setTimeout(moveCountryListToContainerForSmallAndLaptop, 30);
                    }
                }
            });

            // Observe body for additions (only childList+subtree; light)
            observer.observe(document.body, { childList: true, subtree: true });

            // expose for debugging if needed
            window._iti_countrylist_observer = observer;
        } catch (err) {
            // fail silently
        }
    })();

    // Call once after init (small delay to let plugin create DOM)
    setTimeout(function () {
        moveCountryListToContainerForSmallAndLaptop();
    }, 60);

    // Re-run on resize/orientationchange to adapt (debounced)
    window.addEventListener("resize", function () {
        clearTimeout(window._iti_move_timer);
        window._iti_move_timer = setTimeout(moveCountryListToContainerForSmallAndLaptop, 120);
    });
    window.addEventListener("orientationchange", function () {
        setTimeout(moveCountryListToContainerForSmallAndLaptop, 160);
    });

    // Also adjust position right after user clicks to open (ensure first-click works)
    const clickTargets = [];
    if (flagContainer) clickTargets.push(flagContainer);
    const sel = itiContainer.querySelector(".iti__selected-dial-code");
    if (sel) clickTargets.push(sel);

    clickTargets.forEach(function (el) {
        el.addEventListener("click", function () {
            setTimeout(function () {
                moveCountryListToContainerForSmallAndLaptop();

                // If still overflowing viewport bottom, apply fixed fallback (mobile)
                const list = itiContainer.querySelector(".iti__country-list");
                if (!list) return;
                const rect = list.getBoundingClientRect();
                if (rect.bottom > (window.innerHeight || document.documentElement.clientHeight) - 12) {
                    // make it appear above bottom with fixed positioning
                    list.style.position = "fixed";
                    list.style.left = "8px";
                    list.style.right = "8px";
                    list.style.bottom = "80px";
                    list.style.width = "auto";
                    list.style.maxHeight = "55vh";
                    list.style.borderRadius = "8px";
                    list.style.zIndex = "100000";
                }
            }, 80);
        });
    });

