document.addEventListener("DOMContentLoaded", function() {
    const phoneInput = document.querySelector("#wpforms-12352-field_4");
    const form12352  = document.querySelector("#wpforms-form-12352");

    if (!phoneInput || !form12352) return;

    function setupIntlTelInput(input) {
        const iti = window.intlTelInput(input, {
            separateDialCode: true,
            autoPlaceholder: "off",
            initialCountry: ""
        });
     

        // .iti container ko wrapper ki tarah use karo
        const itiContainer = input.closest(".iti");
        if (!itiContainer) return iti;

        itiContainer.classList.add("phone-wrapper-custom");


        // CUSTOM SELECTED AREA (left side)
        const selectedDialCode = document.createElement("div");
        selectedDialCode.className = "custom-selected-dial";
        selectedDialCode.innerHTML =
            '<span class="placeholder">Select Country&nbsp;<i class="fa fa-caret-down" aria-hidden="true"></i></span>';

        // input se pehle insert karo
        itiContainer.insertBefore(selectedDialCode, input);

        // DROPDOWN
        const dropdown = document.createElement("ul");
        dropdown.className = "custom-country-dropdown";
        itiContainer.appendChild(dropdown);

        // ERROR DIV (container ke baad)
        const errorDiv = document.createElement("div");
        errorDiv.className = "custom-phone-error";
        errorDiv.textContent = "";
        itiContainer.parentNode.insertBefore(errorDiv, itiContainer.nextSibling);

        // ----- COUNTRY LIST LOAD -----
        const loadCountries = () => {
            const countryData = (window.intlTelInputGlobals && window.intlTelInputGlobals.getCountryData)
                ? window.intlTelInputGlobals.getCountryData()
                : [];

            if (!countryData || !countryData.length) {
                console.warn("No country data found from intl-tel-input.");
                return;
            }

            // sort alphabetically
            countryData.sort((a, b) => {
                const nameA = (a.name || "").toLowerCase();
                const nameB = (b.name || "").toLowerCase();
                if (nameA < nameB) return -1;
                if (nameA > nameB) return 1;
                return 0;
            });

            countryData.forEach(c => {
                const name = c.name;
                const dial = "+" + (c.dialCode || "");
                const code = (c.iso2 || "").toLowerCase();
                if (!name || !dial || !code) return;

                const li = document.createElement("li");
                li.dataset.code = code;
                li.dataset.dialCode = dial;

                li.innerHTML =
                    '<div class="iti__flag-box"><div class="iti__flag iti__' + code + '"></div></div>' +
                    '<strong>' + dial + '</strong>' +
                    '<span>' + name + '</span>';

                li.onclick = () => {
                    iti.setCountry(code);
                    selectedDialCode.innerHTML =
                        '<div class="iti__flag-box"><div class="iti__flag iti__' + code + '"></div></div>' +
                        '<strong>' + dial + '</strong>';
                    dropdown.style.display = "none";
                    errorDiv.style.display = "none";
                    selectedDialCode.dataset.countrySelected = "true";
                };

                dropdown.appendChild(li);
            });
        };
        loadCountries();

        // TOGGLE DROPDOWN
        selectedDialCode.addEventListener("click", function(e) {
            e.stopPropagation();
            dropdown.style.display = (dropdown.style.display === "block") ? "none" : "block";
        });

        document.addEventListener("click", function(e) {
            if (!dropdown.contains(e.target) && e.target !== selectedDialCode) {
                dropdown.style.display = "none";
            }
        });

        // only numbers allowed
        input.addEventListener("keypress", function(e) {
            if (!/[0-9]/.test(e.key)) e.preventDefault();
        });
        input.addEventListener("input", function() {
            if (input.value.length > 12) {
                input.value = input.value.slice(0, 12);
            }
        });

        input._errorDiv = errorDiv;
        input._selectedDialCode = selectedDialCode;
        return iti;
    }

    const itiMain = setupIntlTelInput(phoneInput);

    function formatNumberWithDash(iti, input) {
        try {
            const countryData = iti.getSelectedCountryData() || {};
            const dialCode    = countryData.dialCode || "";
            let fullNumber    = "";

            if (window.intlTelInputUtils) {
                fullNumber = iti.getNumber(intlTelInputUtils.numberFormat.E164);
            } else {
                fullNumber = iti.getNumber();
            }

            const cleanedNational = fullNumber
                .replace("+" + dialCode, "")
                .replace(/^[-\s]+/, "");
            return "+" + dialCode + "-" + cleanedNational;
        } catch (err) {
            return input.value;
        }
    }



    // FORM VALIDATION (UPDATED WITH 10–14 DIGIT CHECK)
form12352.addEventListener("submit", function(e) {

    if (phoneInput && itiMain) {

        const countryData       = itiMain.getSelectedCountryData();
        const dialCode          = countryData ? countryData.dialCode : "";
        const countryCode       = countryData ? countryData.iso2 : "";
        const number            = phoneInput.value.trim();
        const rawNumber         = number.replace(/\D/g, '');
        const errorDiv          = phoneInput._errorDiv;
        const selectedDialCode  = phoneInput._selectedDialCode;
        const isCountrySelected = selectedDialCode.dataset.countrySelected === "true";

        // 1️⃣ Reset error
        errorDiv.style.display = "none";

        // 2️⃣ If empty → let WPForms handle required
        if (number === "") {
            return true;
        }

        // 3️⃣ Country not selected
        if (!isCountrySelected || !dialCode || !countryCode) {
            errorDiv.textContent = "Please select a country.";
            errorDiv.style.display = "block";
            e.preventDefault();
            e.stopImmediatePropagation();
            errorDiv.scrollIntoView({ behavior: "smooth", block: "center" });
            return false;
        }

        // 4️⃣ Minimum 10 digits
        if (rawNumber.length < 10) {
            errorDiv.textContent = "Phone number must be at least 10 digits.";
            errorDiv.style.display = "block";
            e.preventDefault();
            e.stopImmediatePropagation();
            errorDiv.scrollIntoView({ behavior: "smooth", block: "center" });
            return false;
        }

        // 5️⃣ Maximum 14 digits
        if (rawNumber.length > 14) {
            errorDiv.textContent = "Phone number cannot exceed 14 digits.";
            errorDiv.style.display = "block";
            e.preventDefault();
            e.stopImmediatePropagation();
            errorDiv.scrollIntoView({ behavior: "smooth", block: "center" });
            return false;
        }

        // 6️⃣ Format with dash
        phoneInput.value = "+" + dialCode + "-" + rawNumber;
    }
});
   
});
