<script>
(function () {

  // debounce helper (lightweight)
  function debounce(fn, wait) {
    let t;
    return function () {
      clearTimeout(t);
      t = setTimeout(fn, wait || 120);
    };
  }

  function updateVpClass() {
    var w = window.innerWidth || document.documentElement.clientWidth;

    // Laptop Only: 1360px to 1600px
    if (w >= 1360 && w <= 1600) {
      document.documentElement.classList.add('vp-1360-1600');
    } else {
      document.documentElement.classList.remove('vp-1360-1600');
    }
  }

  // Run once after DOM is ready (non-blocking)
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', updateVpClass);
  } else {
    updateVpClass();
  }

  // Run on resize (debounced)
  window.addEventListener('resize', debounce(updateVpClass, 120));

  // Run on orientation change
  window.addEventListener('orientationchange', function () {
    setTimeout(updateVpClass, 140);
  });

})();
</script>
