  <script>
(function(){
  if(!window.dataLayer) return;

  /* ---------- FORM MAPPING ---------- */
  var FORM_MAPPING={
    'wpforms-form-10740':'Footer Contact Form',
    'wpforms-form-20583':'Contact Page Form',
    'wpforms-form-12352':'Popup Form WagerGeeks'
  };

  function getFormName(f,id){
    try{
      return FORM_MAPPING[id] || f?.getAttribute('aria-label') || id || 'unknown_form';
    }catch(e){
      return 'unknown_form';
    }
  }

  function push(ev,data){
    try{
      data=data||{};
      data.event=ev;
      data.page_path=location.pathname+location.search;
      window.dataLayer.push(data);
      if(typeof gtag==='function'){
        gtag('event',ev,data);
      }
    }catch(e){}
  }

  /* ---------- TEXT SELECTION ---------- */
  document.addEventListener('mouseup',function(){
    try{
      var sel=window.getSelection().toString().trim();
      if(sel && sel.length>=3){
        push('text_selection',{
          selection_text:sel.slice(0,200)
        });
      }
    }catch(e){}
  });

  /* ---------- CONTENT COPY ---------- */
  document.addEventListener('copy',function(){
    try{
      var t=window.getSelection().toString().trim();
      if(t){
        push('content_copy',{
          copied_text:t.slice(0,200)
        });
      }
    }catch(e){}
  });

  /* ---------- CLICK TRACKING ---------- */
  document.addEventListener('click',function(e){
    var a=e.target.closest('a');
    if(a){
      var href=a.getAttribute('href')||'';
      var txt=(a.innerText||'').trim().slice(0,200);

      if(/^tel:/i.test(href)){
        push('phone_click',{phone:href.replace(/^tel:/i,''),text:txt});
      }
      else if(/^mailto:/i.test(href)){
        push('email_click',{email:href.replace(/^mailto:/i,''),text:txt});
      }
      else if(href.indexOf('../index.html')!==-1){
        push('blog_click',{url:href,text:txt});
      }

      if(a.closest('nav,.elementor-nav-menu,.premium-nav-menu-container')){
        push('menu_click',{menu_text:txt,menu_url:href});
      }
    }

    var btn=e.target.closest('button,.btn,.cta');
    if(btn){
      push('cta_click',{
        button_text:(btn.innerText||'').trim().slice(0,200)
      });
    }
  },true);

  /* ---------- FAQ TOGGLE ---------- */
  document.addEventListener('click',function(e){
    var acc=e.target.closest('.elementor-accordion-item,.e-n-accordion-item');
    if(!acc) return;
    var q=(acc.innerText||'').split('\n')[0].slice(0,100);
    push('faq_toggle',{
      faq:q,
      state:acc.classList.contains('elementor-active')?'open':'close'
    });
  });

  /* ---------- FORM SUBMIT INITIATED ---------- */
  document.addEventListener('submit',function(e){
    var f=e.target.closest('form');
    if(!f) return;

    var id=f.id||'unknown_form';
    var name=getFormName(f,id);

    try{
      sessionStorage.setItem('wg_form_id',id);
      sessionStorage.setItem('wg_form_name',name);
    }catch(e){}

    push('form_submit_initiated',{
      form_id:id,
      form_name:name
    });
  },true);

  /* ---------- THANK YOU PAGE SUCCESS ---------- */
  if(location.pathname.toLowerCase().includes('thank-you')){
    push('form_submit_success',{
      form_id:sessionStorage.getItem('wg_form_id'),
      form_name:sessionStorage.getItem('wg_form_name'),
      source:'thank_you_page'
    });
    try{ sessionStorage.clear(); }catch(e){}
  }

  /* ---------- INIT ---------- */
  push('wagergeeks_tracking_initialized');

})();
</script>
